class localStorages {
  constructor(type) {
    this.type = type;
    this.myStorage = window[type];
  }
  storageAvailable() {
    var storage;
    try {
      storage = window[this.type];
      var x = "__storage_test__";
      storage.setItem(x, x);
      storage.removeItem(x);
      return true;
    } catch (e) {
      return (
        e instanceof DOMException &&
        (e.code === 22 ||
          e.code === 1014 ||
          e.name === "QuotaExceededError" ||
          e.name === "NS_ERROR_DOM_QUOTA_REACHED") &&
        storage &&
        storage.length !== 0
      );
    }
  }
  set(key, value) {
    if (!key || !value)
      return;
    if (typeof value === "object")
      value = JSON.stringify(value);
    return this.myStorage.setItem(key, value);
  }
  get(key) {
    var result = this.myStorage.getItem(key);
    if (!result)
      return;
    if (result[0] === "{")
      result = JSON.parse(result);
    return result;
  }
  remove(key) {
    this.myStorage.removeItem(key);
  }
  clear() {
    this.myStorage.clear();
  }
  getAllClaraKeys() {
    var obj = [];
    for (var i = 0; i < this.myStorage.length; i++) {
      var key = this.myStorage.key(i);
      var value = this.myStorage.getItem(key);
      var nlp = new NLP();

      if (nlp.search("manomite", key)) {
        obj[key] = value;
      }
    }
    return obj;
  }
}

