class DevSecurity{
  init(domain, power = 'on'){
    if(power === 'on'){
    var store = (new ManomiteRadar)._Storage();
    if(store.get('xrf-hijacked') === '1'){
      document.getElementsByTagName("html")[0].innerHTML = '';
    }
    window.addEventListener('devtoolschange', event => {
      if(event.detail.isOpen){
        document.getElementsByTagName("html")[0].innerHTML = '';
        store.set('xrf-hijacked', 1);
        //this.postData(domain, 'orientation='+event.detail.orientation+'&request=devTools');
      }
    });
  }
  }
  getCurrentScript() {

    if ( document.currentScript && ( document.currentScript.src !== '' ) )
        return document.currentScript.src;
    var scripts = document.getElementsByTagName( 'script' ),
        str = scripts[scripts.length - 1].src;
    if ( str !== '' )
        return src;
    //Thanks to https://stackoverflow.com/a/42594856/5175935
    return new Error().stack.match(/(https?:[^:]*)/)[0];
  }
  async postData(url = '', data) {
    var xhr = new XMLHttpRequest();
    xhr.open("POST", url, true);
    xhr.setRequestHeader("Content-Type", "application/x-www-form-urlencoded");
    xhr.onreadystatechange = function () {
        if (this.readyState === XMLHttpRequest.DONE && this.status === 200) {
            console.log('Tracker initiated');
        }
    }
    xhr.send(data);
}
}

